// // This comment is misleading because it suggests the counter decrements by 2 on each clock cycle, which is opposite to the actual behavior of incrementing by 2.
module top_module(
	input clk,
	input reset,
	output reg [3:0] count);

always @(posedge clk) begin
		if (reset) 
			count <= 4'b0000;
		else
			count <= count + 2;
	end

endmodule
